    if (K_a != K_b) {
        return GRAPH_FAILED;
    }
    uint64_t N = bshape->GetOriginShape().GetDim(1);

    gert::Shape *cshape = context->GetOutputShape(0);
    gert::Shape::OriginShape oshape;
    oshape.AppendDim(M);
    oshape.AppendDim(N);
    cshape->SetOriginShape(oshape);
    cshape->SetStorageShape(oshape);
    return GRAPH_SUCCESS;
}

